mapper.select:
select  

    and current_flag = 1




                and site in
                #{it}

            and site like concat('%', #{site}, '%')




            and sku in #{it}
            and sku like concat('%', #{sku}, '%')



        and product_name like concat('%', #{productName}, '%')



            and sku_level in #{it}
            and sku_level = #{skuLevel}



        and owner_name like concat('%', #{ownerName}, '%')






                and overseas_onway between #{overseasOnway_val} and #{overseasOnway_val2}

             and overseas_onway is null 
             and overseas_onway is not null 
             and overseas_onway ${overseasOnway_op} #{overseasOnway_val} 





                and overseas_sellable between #{overseasSellable_val} and #{overseasSellable_val2}

             and overseas_sellable is null 
